import { execution } from '@dynatrace-sdk/automation-utils';
import { problemsClient } from '@dynatrace-sdk/client-classic-environment-v2';

export default async function ({ executionId }) {
  const { input } = await fetch(`/platform/automation/v1/executions/${executionId}`).then((res) => res.json());

  try {
    let updateBody = {};

    if (input.priorityLevel) {
      updateBody.priorityLevel = input.priorityLevel;
    }

    if (input.rootCauseAnalysis) {
      updateBody.rootCauseAnalysis = input.rootCauseAnalysis;
    }

    if (input.assignee) {
      updateBody.assignee = input.assignee;
    }

    // Add comment if provided
    if (input.comments) {
      const commentResult = await problemsClient.addCommentToProblem({
        problemId: input.problemId,
        body: { comment: input.comments }
      });
      console.log('Comment added');
    }

    // Update problem metadata
    const updated = await problemsClient.updateProblem({
      problemId: input.problemId,
      body: updateBody
    });

    console.log(`Updated problem ${input.problemId}`);

    return {
      problemId: input.problemId,
      updates: updateBody,
      commentAdded: !!input.comments,
      success: true
    };
  } catch (error) {
    console.error('Error updating problem:', error);
    throw new Error(`Failed to update problem: ${error}`);
  }
}
